import requests

def test_get_api_export_skill_zip_not_found():
    base_url = "http://localhost:8000"
    non_existent_skill_name = "this-skill-does-not-exist-12345"
    url = f"{base_url}/api/export/{non_existent_skill_name}/zip"
    try:
        response = requests.get(url, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"
    assert response.status_code == 404, f"Expected 404 but got {response.status_code}"
    # The response text or json should contain indication that zip not found for given skill name
    # Check for known message substring; can be text or json
    if response.headers.get("content-type", "").startswith("application/json"):
        json_data = {}
        try:
            json_data = response.json()
        except Exception:
            pass
        assert any("zip not found" in str(v).lower() for v in json_data.values()) or "not found" in str(json_data).lower(), \
            f"Response JSON does not indicate zip not found: {json_data}"
    else:
        # Plain text or other content
        assert "not found" in response.text.lower(), f"Response text does not indicate zip not found: {response.text}"

test_get_api_export_skill_zip_not_found()

import requests

def test_get_api_export_single_file_path_traversal_attempt():
    base_url = "http://localhost:8000"
    skill_name = "active-recall-study-system"
    # Path traversal attempt
    file_path = "../../etc/passwd"
    url = f"{base_url}/api/export/{skill_name}/{file_path}"
    headers = {
        "Accept": "*/*"
    }

    try:
        response = requests.get(url, headers=headers, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code in (400, 404), f"Expected status code 400 or 404, got {response.status_code}"
    # Optional: check response content to confirm invalid path message
    try:
        json_resp = response.json()
        if response.status_code == 400:
            assert "invalid" in str(json_resp).lower() or "path" in str(json_resp).lower()
    except ValueError:
        # Response is not JSON, still accept 400 or 404 as valid
        pass

test_get_api_export_single_file_path_traversal_attempt()

import requests

def test_post_api_export_copy_file_content():
    base_url = "http://localhost:8000"
    endpoint = "/api/export/copy"
    skill_name = "active-recall-study-system"
    file_path = "SKILL.md"
    url = base_url + endpoint
    payload = {
        "skill_name": skill_name,
        "file_path": file_path
    }
    headers = {
        "Accept": "application/json",
        "Content-Type": "application/json"
    }
    timeout = 30

    try:
        response = requests.post(url, json=payload, headers=headers, timeout=timeout)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"
    try:
        json_response = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert "content" in json_response, "Response JSON missing 'content'"
    assert "file_path" in json_response, "Response JSON missing 'file_path'"
    assert json_response["file_path"] == file_path, f"Response file_path expected '{file_path}' but got '{json_response['file_path']}'"
    assert isinstance(json_response["content"], str) and len(json_response["content"]) > 0, "Content should be a non-empty string"

test_post_api_export_copy_file_content()
